const detectExposures = async (
  hre: HardhatRuntimeEnvironment,
): Promise<ContractExposures[]> => {
  const names = await hre.artifacts.getAllFullyQualifiedNames();
  const contractExposures: ContractExposures[] = [];

  for (let i = 0; i < names.length; i++) {
    const name = names[i];
    if (name.includes("@fhenixprotocol/contracts/")) continue;

    const artifact = await hre.artifacts.readArtifact(name);
    const funcExposures = detectContractExposure(artifact.abi);
    if (funcExposures.length > 0) {
      contractExposures.push({
        contract: name,
        funcExposures: funcExposures,
        count: funcExposures.reduce((acc, item) => acc + item.count, 0),
      });
    }
  }

  return contractExposures;
};

for (const varDecl of contractDef.nodes) {
    if (isNodeType('VariableDeclaration', varDecl)) {
        if (varDecl.mutability === 'immutable') {
            if (
                !skipCheck('state-variable-immutable', contractDef) &&
                !skipCheck('state-variable-immutable', varDecl)
            ) {
                yield {
                    kind: 'state-variable-immutable',
                    name: varDecl.name,
                    src: decodeSrc(varDecl),
                };
            }
        } else if (!varDecl.constant && !isNullish(varDecl.value)) {
            // Assignments are only a concern for non-immutable variables
            if (
                !skipCheck('state-variable-assignment', contractDef) &&
                !skipCheck('state-variable-assignment', varDecl)
            ) {
                yield {
                    kind: 'state-variable-assignment',
                    name: varDecl.name,
                    src: decodeSrc(varDecl),
                };
            }
        }
    }
}

