Assertion.addMethod("hexEqual", function (this: any, other: string) {
  const subject = this._obj;
  const isNegated = this.__flags.negate === true;

  // check that both values are proper hex strings
  const isHex = (a: string) => /^0x[0-9a-fA-F]*$/.test(a);
  for (const element of [subject, other]) {
    if (!isHex(element)) {
      this.assert(
        isNegated, // trick to make this assertion always fail
        `Expected "${subject}" to be a hex string equal to "${other}", but "${element}" is not a valid hex string`,
        `Expected "${subject}" not to be a hex string equal to "${other}", but "${element}" is not a valid hex string`,
      );
    }
  }

  // compare values
  const extractNumeric = (hex: string) => hex.replace(/^0x0*/, "");
  this.assert(
    extractNumeric(subject.toLowerCase()) ===
      extractNumeric(other.toLowerCase()),
    `Expected "${subject}" to be a hex string equal to "${other}"`,
    `Expected "${subject}" NOT to be a hex string equal to "${other}", but it was`,
    `Hex string representing the same number as ${other}`,
    subject,
  );
});

class SolidityError extends Error {
  public readonly code: number = REVERT_ERROR_CODE;
  public readonly solidityStack: string;

  constructor(
    message: string,
    public readonly stackTrace: SolidityStackTrace,
    public readonly data: string,
    public readonly transactionHash?: string,
  ) {
    super(message);
    this.name = "SolidityError";
    this.solidityStack =
      stackTrace.length !== 0
        ? stackTrace.map(encodeStackTraceEntry).reverse().join("\n")
        : "Internal error when encoding SolidityError";

    Object.defineProperty(this, Symbol.for("nodejs.util.inspect.custom"), {
      value: () =>
        this.stack !== undefined
          ? this.stack
          : "Internal error when encoding SolidityError",
      writable: false,
      enumerable: false,
      configurable: true,
    });
  }
}

data.deployments.forEach(deployment => {
  const stats: any = {};
  if (deployment.gasData.length === 0) return;

  stats.cost = (deployment.cost === undefined) ? chalk.grey("-") : deployment.cost;

  if (deployment.min && deployment.max) {
    const uniform = deployment.min === deployment.max;
    stats.min = uniform ? chalk.grey("-") : chalk.cyan(commify(deployment.min!));
    stats.max = uniform ? chalk.grey("-") : chalk.red(commify(deployment.max!));
  }

  const section: any = [];
  section.push({ hAlign: "left", colSpan: 2, content: deployment.name });
  section.push({ hAlign: "right", content: stats.min });
  section.push({ hAlign: "right", content: stats.max });
  section.push({ hAlign: "right", content: commify(deployment.executionGasAverage!) });
  section.push({
    hAlign: "right",
    content: optionalColor(`${deployment.percent!} %`)
  });
  section.push({
    hAlign: "right",
    content: chalk.green(stats.cost.toString())
  });

  deployRows.push(section);
});

try {
  await fsPromises.copyFile(source, destination);
} catch (e) {
  ensureNodeErrnoExceptionError(e);
  if (e.code === "ENOENT") {
    if (!(await exists(source))) {
      throw new FileNotFoundError(source, e);
    }
    if (!(await exists(destination))) {
      throw new FileNotFoundError(destination, e);
    }
  }

  // On linux, trying to copy a directory will throw EISDIR,
  // on Windows it will throw EPERM, and on macOS it will throw ENOTSUP.
  if (e.code === "EISDIR" || e.code === "EPERM" || e.code === "ENOTSUP") {
    if (await isDirectory(source)) {
      throw new IsDirectoryError(source, e);
    }
    if (await isDirectory(destination)) {
      throw new IsDirectoryError(destination, e);
    }
  }

  throw new FileSystemAccessError(e.message, e);
}

