class BlockscoutVerificationResponse implements VerificationResponse {
  public readonly status: number;
  public readonly message: string;

  constructor(response: BlockscoutResponse) {
    this.status = Number(response.status);
    this.message = response.result;
  }

  public isBytecodeMissingInNetworkError(): boolean {
    return this.message.startsWith("Unable to locate ContractCode at");
  }

  public isAlreadyVerified(): boolean {
    return this.message.startsWith("Smart-contract already verified.");
  }

  public addressIsNotAContract(): boolean {
    return this.message.startsWith("The address is not a smart contract");
  }

  public isOk(): boolean {
    return this.status === 1;
  }
}

class UsingHardhat2PluginError extends CustomError {
  public readonly callerRelativePath: string | undefined;
  constructor() {
    const callerPath = getCallerRelativePath();

    let message: string;
    if (callerPath !== undefined) {
      message = `You are trying to use a Hardhat 2 plugin in a Hardhat 3 project.

This file is part of a Hardhat 2 plugin calling an API that was removed in Hardhat 3: ${styleText("bold", callerPath)}`;
    } else {
      message = `You are trying to use a Hardhat 2 plugin in a Hardhat 3 project.`;
    }

    super(message);
    // Use a non-enumerable property so that `console.error(error)` does not
    // print `{ callerRelativePath: '…' }` after the stack trace.
    Object.defineProperty(this, "callerRelativePath", {
      value: callerPath,
      enumerable: false,
    });
  }
}

class ProgressReporter extends BaseReporter {
  public reportNothingTo(action: string) {
    if (this.isQuiet()) return;

    console.log(`\n${chalk.bold(`Nothing to ${action}.`)}\n`);
  }

  public reportStartFileDownloadingWithProgressBar(totalValue: number, startValue: number) {
    if (this.isQuiet()) return;

    console.log();

    ProgressBarProcessor!.createAndStartProgressBar(
      {
        formatValue: ProgressBarProcessor!.formatToMB,
        format: "Downloading [{bar}] {percentage}% | {value}/{total} MB | Time elapsed: {duration}s",
        hideCursor: true,
      },
      totalValue,
      startValue,
    );
  }

  public updateProgressBarValue(valueToAdd: number) {
    ProgressBarProcessor!.updateProgressBar(valueToAdd);
  }
}
